'use strict';

/**
* Subtract a scalar constant from each element in a single-precision floating-point strided array.
*
* @module @stdlib/blas-ext-base-sxsa
*
* @example
* import Float32Array from '@stdlib/array-float32';
* import sxsa from '@stdlib/blas-ext-base-sxsa';
*
* var x = new Float32Array( [ -2.0, 1.0, 3.0, -5.0, 4.0, 0.0, -1.0, -3.0 ] );
*
* sxsa( x.length, 5.0, x, 1 );
* // x => <Float32Array>[ -7.0, -4.0, -2.0, -10.0, -1.0, -5.0, -6.0, -8.0 ]
*
* @example
* import Float32Array from '@stdlib/array-float32';
* import sxsa from '@stdlib/blas-ext-base-sxsa';
*
* var x = new Float32Array( [ -2.0, 1.0, 3.0, -5.0, 4.0, 0.0, -1.0, -3.0 ] );
*
* sxsa.ndarray( x.length, 5.0, x, 1, 0 );
* // x => <Float32Array>[ -7.0, -4.0, -2.0, -10.0, -1.0, -5.0, -6.0, -8.0 ]
*/

// MODULES //

var join = require( 'path' ).join;
import tryRequire from '@stdlib/utils-try-require';
import isError from '@stdlib/assert-is-error';
import main from './main.js';


// MAIN //

var sxsa;
var tmp = tryRequire( join( __dirname, './native.js' ) );
if ( isError( tmp ) ) {
	sxsa = main;
} else {
	sxsa = tmp;
}


// EXPORTS //

export default sxsa;

// exports: { "ndarray": "sxsa.ndarray" }
