'use strict';

// MODULES //

import stride2offset from '@stdlib/strided-base-stride2offset';
import ndarray from './ndarray.js';


// MAIN //

/**
* Cumulatively tests whether every element in a strided array is truthy.
*
* @param {PositiveInteger} N - number of indexed elements
* @param {Collection} x - input array
* @param {integer} strideX - stride length for `x`
* @param {Collection} out - output array
* @param {integer} strideOut - stride length for `out`
* @returns {Collection} output array
*
* @example
* var x = [ 1, 1, 0, 0 ];
* var out = [ false, false, false, false ];
*
* gcuevery( x.length, x, 1, out, 1 );
* // out => [ true, true, false, false ]
*/
function gcuevery( N, x, strideX, out, strideOut ) {
	var ox = stride2offset( N, strideX );
	var oo = stride2offset( N, strideOut );
	return ndarray( N, x, strideX, ox, out, strideOut, oo );
}


// EXPORTS //

export default gcuevery;
